 221→    public function getIndividual(int $sfuserId): array
 222→    {
 223→        $redisKey = config('my_project.site_key').':'.static::REDIS_KEY_PREFIX.$sfuserId;
 224→        // shared:CHN:App\Service\NotifyNumberService__SFUSER_IDS__:1   存储sfuser_id = 1的信息
 225→        return array_map('intval', redis('shared')->hgetall($redisKey)) + array_combine(
 226→            static::NOTIFY_TYPES,
 227→            array_fill(0, count(static::NOTIFY_TYPES), 0)
 228→        );
