 236→    public function clearCache(): array
 237→    {
 238→        $sfuserIds = redis('shared')->smembers(config('my_project.site_key').':'.static::REDIS_KEY_SFUSER_IDS);
 239→
 240→        $keys = array_map(function ($sfuserId) {
 241→            return config('my_project.site_key').':'.static::REDIS_KEY_PREFIX.$sfuserId;
 242→        }, $sfuserIds);
 243→
 244→        redis('shared')->del($keys);
 245→        redis('shared')->del(config('my_project.site_key').':'.static::REDIS_KEY_SFUSER_IDS);
 246→
 247→        info('[NotifyNumber] 清空待办缓存', ['sfuser_count' => count($sfuserIds)]);
 248→
 249→        return $sfuserIds;
 250→    }
