 285→    /**
 286→     * 绩效相关.
 287→     *
 288→     * @return array
 289→     */
 290→    public function initPerformance(): array
 291→    {
 292→        $data = [];
 293→        [$year, $month] = PerformanceUtil::yearAndMonthOfLastMonth();
 294→        $data['performance_publisher'] = PerformanceGroup::where([
 295→            'year' => $year,
 296→            'month' => $month,
 297→        ])->where('publisher_id', '<>', 0)
 298→            ->where('is_closed', 0)
 299→            ->whereIn('status', Performance::PUBLISHERS_CAN_EDIT)
 300→            ->selectRaw('count(*) as count, publisher_id')
 301→            ->having('count', '>', 0)
 302→            ->groupBy('publisher_id')->pluck('count', 'publisher_id')->toArray();
 303→
 304→        $data['performance_appraiser'] = Performance::where([
 305→            'year' => $year,
 306→            'month' => $month,
 307→        ])
 308→            ->where('appraiser_id', '<>', 0)
 309→            ->whereIn('status', Performance::APPRAISER_CAN_EDIT)
 310→            ->selectRaw('count(*) as count, appraiser_id')
 311→            ->having('count', '>', 0)
 312→            ->groupBy('appraiser_id')->pluck('count', 'appraiser_id')->toArray();
 313→
 314→        return $this->flushData($data);
 315→    }
