 317→    /**
 318→     * 考勤相关.
 319→     *
 320→     * @return array
 321→     */
 322→    public function initAttendanceUnusual(): array
 323→    {
 324→        if (SiteService::app()->isNot(SiteService::CHN)) {
 325→            return [];
 326→        }
 327→        $data = [];
 328→
 329→        $today = date('Y-m-d');
 330→        $startDate = date('Y-m-01');
 331→        // 查找上月结算日
 332→        $query = AttendanceCalculateDate::where('year', (int)date('Y'))->where('month', (int)date('m'))->first();
 333→        if ($query == null || $today <= $query->lock_approval_date) {
 334→            $startDate = date('Y-m-01', strtotime('-1 month'));
 335→        }
 336→        // 考勤异常
 337→        $data['attendance_unusual'] = AttendanceData::join('sfusers as sf', 'sf.id', '=', 'attendance_data.sfuser_id')
 338→            ->whereColumn('sf.entry_time', '<=', 'attendance_data.attend_date')->where('attend_date', '>=', $startDate)
 339→            ->where('attend_date', '<=', $today)->where('is_unusual', 1)
 340→            ->selectRaw('count(*) as count, sfuser_id')->groupBy('sfuser_id')->having('count', '>', 0)
 341→            ->pluck('count', 'sfuser_id')->toArray();
 342→
 343→        return $this->flushData($data);
 344→    }
