 571→    /**
 572→     * 离职权限相关.
 573→     *
 574→     * @return array
 575→     */
 576→    public function initResignationPermission(): array
 577→    {
 578→        $data = [];
 579→        $data['resignation_permission_to_be_executed'] = [];
 580→        // 统计未执行
 581→        $notExecutedTypeCount = ResignationPermissionSfuser::whereStatus(ResignationPermission::NOT_EXECUTED)
 582→            ->selectRaw('type, count(*) as count')
 583→            ->groupBy('type')->having('count', '>', 0)
 584→            ->pluck('count', 'type')
 585→            ->toArray();
 586→        if (app()->environment(['unit_test', 'testing'])) {
 587→            // 临时记录
 588→            foreach ($notExecutedTypeCount as $t => $c) {
 589→                info("{$t}: {$c}");
 590→            }
 591→        }
 592→
 593→        // 统计延期执行，且延期日期已至/已过
 594→        //  延期执行的关闭权限id
 595→        $postponedAll = ResignationPermissionSfuser::alias('rps')
 596→            ->join('resignation_permissions as rp', 'rps.type', '=', 'rp.type')
 597→            ->where('is_on', 1)
 598→            ->whereStatus(ResignationPermission::DEFER_TO_EXECUTE)
 599→            ->pluck('rps.id')->toArray();
 600→        //  最新延期操作记录
 601→        $operationTableIds = ResignationPermissionOperationRecord::whereIn('resignation_permission_sfusers_id', $postponedAll)
 602→            ->groupBy('resignation_permission_sfusers_id')
 603→            ->selectRaw("SUBSTRING_INDEX(GROUP_CONCAT(id order by created_at desc), ',', 1) as operation_id")
 604→            ->pluck('operation_id')->toArray();
 605→        //  延期日期小于等于当天的
 606→        $postponedSfuserTableIds = ResignationPermissionOperationRecord::whereIn('id', $operationTableIds)
 607→            ->where('postponed_date', '<=', date('Y-m-d', strtotime('now')))
 608→            ->pluck('resignation_permission_sfusers_id')->toArray();
 609→        // 每个类型对应延期需通知的数量
 610→        $postponedTypeCount = ResignationPermissionSfuser::whereId($postponedSfuserTableIds)
 611→            ->selectRaw('type, count(*) as count')
 612→            ->groupBy('type')->having('count', '>', 0)
 613→            ->pluck('count', 'type')
 614→            ->toArray();
 615→
 616→        // 汇总统计每个负责人的通知数目
 617→        $allTypeCount = $notExecutedTypeCount;
 618→        foreach ($postponedTypeCount as $type => $cnt) {
 619→            if (app()->environment(['unit_test', 'testing'])) {
 620→                // 临时记录
 621→                info("{$type}: {$cnt}");
 622→            }
 623→            if (Arr::has($allTypeCount, $type)) {
 624→                $allTypeCount[$type] += $cnt;
 625→            } else {
 626→                $allTypeCount[$type] = $cnt;
 627→            }
 628→        }
 629→        $typeIds = ResignationPermission::whereIsOn(1)->pluck('ids', 'type')->toArray();
 630→        foreach ($allTypeCount as $type => $count) {
 631→            foreach ($typeIds[$type] as $sfuserId) {
 632→                if (!Arr::has($data['resignation_permission_to_be_executed'], $sfuserId)) {
 633→                    $data['resignation_permission_to_be_executed'][$sfuserId] = 0;
 634→                }
 635→                $data['resignation_permission_to_be_executed'][$sfuserId] += $count;
 636→            }
 637→        }
 638→
 639→        return $this->flushData($data);
 640→    }
