 679→        $data['oa_issued'] = WorkflowRequest::whereNotIn('current_state_id', State::COMMON_TYPES)->whereNotIn('process_key', Registry::REIMBURSEMENT_TYPE)->where('is_locked', 0)
 680→            ->selectRaw('user_id as sfuser_id, count(*) as count')->groupBy('sfuser_id')->having('count', '>', 0)
