 682→
 683→        // 待我审批 - 除报销
 684→        $service = new AttendanceService();
 685→        $lock_approval_date = $service->getLockApprovalDate();
 686→        $expiredOperate = $service->expiredOperate($lock_approval_date);
 687→        $startTime = date('Y-m-d', strtotime("{$lock_approval_date} first day of last month")).' 00:00:00';
 688→        $endTime = $lock_approval_date.AttendanceService::$END_TIME;
 689→
 690→        $data['oa_to_be_approved'] = (new ActionerQueryBuilder())->toBeApprovedByMe()->actionIn(Action::APPROVE)
 691→            ->unlocked24($startTime, $endTime, $expiredOperate)->excludeProcessKeys(Registry::REIMBURSEMENT_TYPE)->queryBuilder()
 692→            ->selectRaw('workflow_request_actions.operator_id as sfuser_id, count(*) as count')->groupBy('sfuser_id')->having('count', '>', 0)
 693→            ->pluck('count', 'sfuser_id')->toArray();
 694→
 695→        // 抄送未读 - 除报销
 696→        $data['oa_cc'] = (new StakeholderQueryBuilder())->asCCer()->unread()->excludeProcessKeys(Registry::REIMBURSEMENT_TYPE)->queryBuilder()
 697→            ->selectRaw('workflow_request_stakeholders.user_id as sfuser_id, count(*) as count')->groupBy('sfuser_id')->having('count', '>', 0)
 698→            ->pluck('count', 'sfuser_id')->toArray();
 699→
 700→        // 待我执行
 701→        // 有没有我的执行
 702→        $wsss = WorkflowSpecialStakeholder::alias('wss')
 703→            ->whereIn('type', WorkflowRequestStakeholder::OTHER_TYPES)
 704→            ->select('wss.ids', 'wss.type')->get()->toArray();
 705→        $idss = [];
 706→        foreach ($wsss as $one) {
 707→            $idss = array_unique(array_merge($idss, $one['ids']));
 708→        }
 709→        $data['oa_execute'] = [];
 710→        foreach ($idss as $sfuserId) {
 711→            // 有没有我的执行
 712→            $types = WorkflowSpecialStakeholder::alias('wss')
 713→                ->whereIn('type', WorkflowRequestStakeholder::OTHER_TYPES)
 714→                ->whereJsonContains('ids', $sfuserId)->pluck('wss.type')->toArray();
 715→            if (!empty($types)) {
 716→                $process_keys = [];
 717→                if (in_array(WorkflowRequestStakeholder::ONLY_OFFICE_EXECUTOR_TYPE, $types)) {
 718→                    $process_keys[] = Registry::ONLY_OFFICE;
 719→                }
 720→                if (in_array(WorkflowRequestStakeholder::JIRA_CONFLUENCE_EXECUTOR_TYPE, $types)) {
 721→                    $process_keys[] = Registry::JIRA_CONFLUENCE;
 722→                }
 723→                if (in_array(WorkflowRequestStakeholder::EB_EXECUTOR_TYPE, $types)) {
 724→                    $process_keys[] = Registry::EB;
 725→                }
 726→                if (in_array(WorkflowRequestStakeholder::YA_EXECUTOR_TYPE, $types)) {
 727→                    $process_keys[] = Registry::YA;
 728→                }
 729→                if (in_array(WorkflowRequestStakeholder::X_JIRA_CONFLUENCE_EXECUTOR_TYPE, $types)) {
 730→                    $process_keys[] = Registry::X_JIRA_CONFLUENCE;
 731→                }
 732→                if (in_array(WorkflowRequestStakeholder::AI_TOOLS_EXECUTOR_TYPE, $types)) {
 733→                    $process_keys[] = Registry::AI_TOOLS;
 734→                }
 735→                if (in_array(WorkflowRequestStakeholder::GCP_EXECUTOR_TYPE, $types)) {
 736→                    $process_keys[] = Registry::GCP;
 737→                }
 738→                $exists = OtherPermissionExecute::alias('op')
 739→                    ->whereIn('op.process_key', $process_keys)
 740→                    ->exists();
 741→                if ($exists) {
 742→                    $execute_to_me = DB::table('workflow_requests')
 743→                        ->leftJoin('other_permission_execute', 'other_permission_execute.request_id', '=', 'workflow_requests.id')
 744→                        ->where('workflow_requests.current_state_id', '=', State::COMPLETED)
 745→                        ->whereIn('other_permission_execute.process_key', $process_keys)
 746→                        ->where('other_permission_execute.is_execute', 0)
 747→                        ->count();
 748→                    $data['oa_execute'][$sfuserId] = $execute_to_me;
 749→                }
 750→            }
 751→        }
 752→
 753→        return $this->flushData($data);
 754→    }
