 904→            $ret = redis('shared')->hset($redisKey, $type, $value);
 905→
 906→            redis('shared')->expire($redisKey, static::TTL);
 907→            redis('shared')->sadd(config('my_project.site_key').':'.static::REDIS_KEY_SFUSER_IDS, $sfuserId);
 908→        } else {
 909→            $ret = redis('shared')->hset($redisKey, $type, $value);
 910→        }
 911→
 912→        // 仅当数值真的变化时打日志，展示该用户的待办变化
 913→        if ($oldValue !== $value) {
 914→            info('[NotifyNumber] 待办变化', [
 915→                'sfuserId' => $sfuserId,
 916→                'type' => $type,
 917→                'old' => $oldValue,
 918→                'new' => $value,
 919→                'action' => 'set',
 920→            ]);
 921→        }
 922→
 923→        $this->addNotifySfusers($sfuserId);
 924→
 925→        return $ret;
 926→    }
 927→
 928→    /**
 929→     * 把数据存入redis.
 930→     *
 931→     * @param array $input
 932→     *                     e.g. $input = [
 933→     *                     'oa_issued' => [1 => 1, 2 => 0], // 'sfuser_id' => 'count', 0 需要覆盖
 934→     *                     'oa_to_be_approved' => [1 => 2],
 935→     *                     ];
 936→     * @return array
 937→     */
 938→    protected function flushData(array $input): array
 939→    {
 940→        $sfuserIds = [];
 941→        foreach ($input as $value) {
 942→            $sfuserIds = array_merge($sfuserIds, array_keys($value));
 943→        }
 944→        $sfuserIds = array_values(array_unique($sfuserIds));
 945→
 946→        if (empty($sfuserIds)) {
 947→            return [];
 948→        }
 949→
 950→        foreach ($sfuserIds as $sfuserId) {
 951→            $data = [];
 952→            $redisKey = config('my_project.site_key').':'.static::REDIS_KEY_PREFIX.$sfuserId;
 953→
 954→            // 读取旧值，用于记录变化
 955→            $oldValues = redis('shared')->exists($redisKey)
 956→                ? array_map('intval', redis('shared')->hgetall($redisKey))
 957→                : [];
 958→
 959→            foreach ($input as $key => $value) {
 960→                // 没有 sfuser_id 就不覆盖
 961→                $num = Arr::get($value, $sfuserId, -1);
 962→                if ($num >= 0) {
 963→                    $data[$key] = $num;
 964→                    // 记录每个人的待办变化
 965→                    $oldValue = isset($oldValues[$key]) ? (int)$oldValues[$key] : null;
 966→                    $newValue = (int)$num;
 967→                    if ($oldValue !== $newValue) {
 968→                        info('[NotifyNumber] 待办变化', [
 969→                            'sfuserId' => $sfuserId,
 970→                            'type' => $key,
 971→                            'old' => $oldValue,
 972→                            'new' => $newValue,
 973→                            'action' => 'flush',
 974→                        ]);
 975→                    }
 976→                }
 977→            }
 978→
 979→            redis('shared')->hmset($redisKey, $data);
 980→            redis('shared')->expire($redisKey, static::TTL);
 981→        }
 982→
 983→        redis('shared')->sadd(config('my_project.site_key').':'.static::REDIS_KEY_SFUSER_IDS, ...$sfuserIds);
 984→
 985→        $this->addNotifySfusers($sfuserIds);
 986→
 987→        return $sfuserIds;
 988→    }
 989→
 990→    /**
 991→     * 添加因数字变动需要通知的人.
 992→     *
 993→     * @param mixed $sfuserIds
 994→     * @return void
 995→     */
 996→    protected function addNotifySfusers(mixed $sfuserIds)
 997→    {
 998→        $sfuserIds = Arr::wrap($sfuserIds);
 999→
1000→        if (empty($sfuserIds)) {
1001→            return [];
1002→        }
1003→
1004→        redis('shared')->sadd(static::REDIS_KEY_NEED_NOTIFY_SFUSER_SET, ...$sfuserIds);
1005→
1006→        if (static::$firstRegister && !app()->environment(['unit_test', 'testing'])) {
1007→            register_shutdown_function(function () {
1008→                UpdateWorkbenchNumber::dispatch();
1009→            });
1010→            static::$firstRegister = false;
1011→        }
1012→    }
1013→}
