        },
        {
            index: 3,
            label: this.$t('t290'),
            icon: '',
            route: '/oc-system/cc-application',
        },
    ]
    open_list = [this.$route.path]
    default_active = this.$route.path

    get sealToDoListMap() {
        return this.$store.state.OCSealTodoList
    }
    get paymentToDoListMap() {
        return this.$store.state.OCTodoList
    }
    get loadToDoListMap() {
        return this.$store.state.OCLoanTodoList
    }
    get loanStrikeBalanceToDoListMap() {
        return this.$store.state.OCLoanStrikeBalanceTodoList
    }

    get menus() {
        const allMenus = this.allMenus.map(item => ({
            ...item,
            route: item.route + '/' + this.operationType,
        }))
        let menus = []
        menus = []
        if (this.operationType === 'OCSeal') {
            if (
                this.sealToDoListMap.countingIssuedButNotCompleted ||
                this.sealToDoListMap.countingIssuedButRejected
            ) {
                menus.push({
                    ...allMenus[0],
                    no:
                        this.sealToDoListMap.countingIssuedButNotCompleted +
                        this.sealToDoListMap.countingIssuedButRejected,
                })
            } else {
                menus.push(allMenus[0])
            }
            if (Object.keys(this.sealToDoListMap).includes('countingToBeApprovedByMe')) {
                if (this.sealToDoListMap.countingToBeApprovedByMe) {
                    menus.push({ ...allMenus[1], no: this.sealToDoListMap.countingToBeApprovedByMe })
                } else {
                    menus.push(allMenus[1])
                }
            }
            if (Object.keys(this.sealToDoListMap).includes('countingCc2Me')) {
                if (this.sealToDoListMap.countingCc2Me) {
                    menus.push({ ...allMenus[2], no: this.sealToDoListMap.countingCc2Me })
                } else {
                    menus.push(allMenus[2])
                }
            }
        } else if (this.operationType === 'OCPayment') {
            if (
                this.paymentToDoListMap.countingIssuedButNotCompleted ||
                this.paymentToDoListMap.countingIssuedStrikeBalancePending ||
                this.paymentToDoListMap.countingIssuedButRejected
            ) {
                menus.push({
                    ...allMenus[0],
                    no:
                        this.paymentToDoListMap.countingIssuedButNotCompleted +
                        this.paymentToDoListMap.countingIssuedStrikeBalancePending +
                        this.paymentToDoListMap.countingIssuedButRejected,
                })
            } else {
                menus.push(allMenus[0])
            }
            if (Object.keys(this.paymentToDoListMap).includes('countingToBeApprovedByMe')) {
                if (this.paymentToDoListMap.countingToBeApprovedByMe) {
                    menus.push({ ...allMenus[1], no: this.paymentToDoListMap.countingToBeApprovedByMe })
                } else {
                    menus.push(allMenus[1])
                }
            }
            if (Object.keys(this.paymentToDoListMap).includes('countingCc2Me')) {
                if (this.paymentToDoListMap.countingCc2Me) {
                    menus.push({ ...allMenus[2], no: this.paymentToDoListMap.countingCc2Me })
                } else {
                    menus.push(allMenus[2])
                }
            }
        } else if (this.operationType === 'OCLoan') {
            if (
                this.loadToDoListMap.countingIssuedButNotCompleted ||
                this.loanStrikeBalanceToDoListMap.countingIssuedButNotCompleted
            ) {
                menus.push({
                    ...allMenus[0],
                    no:
                        (this.loadToDoListMap.countingIssuedButNotCompleted ?? 0) +
                        (this.loanStrikeBalanceToDoListMap.countingIssuedButNotCompleted ?? 0),
                })
            } else {
                menus.push(allMenus[0])
            }
            // 借款或冲账有待办项时候才显示，都为undefined时候不展示，注意区分undefined和0的情况
            if (
                this.loadToDoListMap.countingToBeApprovedByMe !== undefined ||
                this.loanStrikeBalanceToDoListMap.countingToBeApprovedByMe !== undefined
            ) {
                if (
                    this.loadToDoListMap.countingToBeApprovedByMe ||
                    this.loanStrikeBalanceToDoListMap.countingToBeApprovedByMe
                ) {
                    menus.push({
                        ...allMenus[1],
                        no:
                            (this.loadToDoListMap.countingToBeApprovedByMe ?? 0) +
                            (this.loanStrikeBalanceToDoListMap.countingToBeApprovedByMe ?? 0),
                    })
                } else {
                    menus.push(allMenus[1])
                }
            }
            // 借款或冲账有待办项时候才显示，都为undefined时候不展示，注意区分undefined和0的情况
            if (
                this.loadToDoListMap.countingCc2Me !== undefined ||
                this.loanStrikeBalanceToDoListMap.countingCc2Me !== undefined
            ) {
                if (this.loadToDoListMap.countingCc2Me || this.loanStrikeBalanceToDoListMap.countingCc2Me) {
                    menus.push({
                        ...allMenus[2],
                        no:
                            (this.loadToDoListMap.countingCc2Me ?? 0) +
                            (this.loanStrikeBalanceToDoListMap.countingCc2Me ?? 0),
                    })
                } else {
                    menus.push(allMenus[2])
                }
            }
        }
        return menus
    }

    async updateTodoList() {
        const loanTodo = await getLoanTodoListAPI()
        const loanStrikeBalanceTodo = await getLoanStrikeBalanceTodoListAPI()
        this.$store.commit('setOCLoanTodoList', loanTodo)
        this.$store.commit('setOCLoanStrikeBalanceTodoList', loanStrikeBalanceTodo)
    }
}
</script>

